sql:
SELECT COUNT(bicycle_id) 
FROM bicycles 
WHERE status = 'available';

external_knowledge:
- 'Floral stations' refers to the rental stations in the bicycle rental system;
- 'Blossomed with the most visits' refers to the stations with the highest number of rentals;
- 'Total time spent under their care' refers to the total rental duration;
- 'Total revenue they have generated' refers to the total cost of all rentals.

sql:
SELECT duration_in_hours, total_cost
FROM rentals
ORDER BY duration_in_hours DESC;

